let data;
const input = $input.item.json;

if (typeof input.body === 'string') {
  data = JSON.parse(input.body);
} else if (typeof input.body === 'object') {
  data = input.body;
} else {
  data = input;
}

const action = (data.action || '').toLowerCase().trim();

if (!action) {
  return [{ json: { error: true, message: 'Action is required. Use one of: status, top_blocked, top_clients, enable, disable, query_log.' } }];
}

const validActions = ['status', 'top_blocked', 'top_clients', 'enable', 'disable', 'query_log'];
if (!validActions.includes(action)) {
  return [{ json: { error: true, message: `Unknown action: ${action}. Use one of: status, top_blocked, top_clients, enable, disable, query_log.` } }];
}

const limit = parseInt(data.limit) || (action === 'query_log' ? 20 : 10);
const duration = parseInt(data.duration) || 0;

return [{ json: { action, limit, duration } }];

const authData = $input.item.json;
const params = $('Parse Parameters').item.json;

// Extract SID from auth response
let sid = '';
if (authData.session && authData.session.sid) {
  sid = authData.session.sid;
} else if (authData.sid) {
  sid = authData.sid;
}

if (!sid) {
  return [{ json: { error: true, message: 'Pi-hole authentication failed. Check your app password.' } }];
}

return [{ json: { ...params, sid } }];

const duration = $('Parse Parameters').item.json.duration;
const body = { blocking: false };
if (duration && duration > 0) body.timer = duration;
return [{ json: { body } }];

const data = $input.item.json;

// Pi-hole v6 nests under queries, clients, gravity objects
const q = data.queries || {};
const c = data.clients || {};
const g = data.gravity || {};

const total = q.total || 0;
const blocked = q.blocked || 0;
const pctBlocked = q.percent_blocked || 0;
const uniqueDomains = q.unique_domains || 0;
const forwarded = q.forwarded || 0;
const cached = q.cached || 0;
const activeClients = c.active || 0;
const totalClients = c.total || 0;
const gravityDomains = g.domains_being_blocked || 0;

// Check blocking status from the action field or infer
const pct = typeof pctBlocked === 'number' ? pctBlocked.toFixed(1) : parseFloat(pctBlocked).toFixed(1);

const qFmt = Number(total).toLocaleString();
const bFmt = Number(blocked).toLocaleString();
const dFmt = Number(gravityDomains).toLocaleString();

const message = `Pi-hole: ${qFmt} queries today, ${bFmt} blocked (${pct}%). ${dFmt} domains on blocklist. ${activeClients} active clients (${totalClients} total).`;

return [{ json: { message, queries_total: total, blocked, percentage: parseFloat(pct), unique_domains: uniqueDomains, forwarded, cached, active_clients: activeClients, total_clients: totalClients, gravity_size: gravityDomains } }];

const data = $input.item.json;
const limit = $('Parse Parameters').item.json.limit;

// Pi-hole v6 returns top_domains as an array of objects or as an object
let domains = [];
if (data.top_domains) {
  if (Array.isArray(data.top_domains)) {
    domains = data.top_domains;
  } else if (typeof data.top_domains === 'object') {
    domains = Object.entries(data.top_domains).map(([domain, count]) => ({ domain, count }));
  }
} else if (data.domains) {
  if (Array.isArray(data.domains)) {
    domains = data.domains;
  } else if (typeof data.domains === 'object') {
    domains = Object.entries(data.domains).map(([domain, count]) => ({ domain, count }));
  }
}

if (domains.length === 0) {
  return [{ json: { message: 'No blocked domains found.', count: 0, domains: [] } }];
}

const limited = domains.slice(0, limit);
const formatted = limited.map((d, i) => ({
  number: i + 1,
  domain: d.domain || d.name || Object.keys(d)[0] || 'unknown',
  count: d.count || d.hits || d[Object.keys(d)[0]] || 0
}));

let message = `Top ${formatted.length} blocked domains: `;
formatted.forEach(d => {
  message += `${d.number}. ${d.domain} (${Number(d.count).toLocaleString()} hits). `;
});

return [{ json: { message: message.trim(), count: formatted.length, domains: formatted } }];

const data = $input.item.json;
const limit = $('Parse Parameters').item.json.limit;

let clients = [];
if (data.top_clients) {
  if (Array.isArray(data.top_clients)) {
    clients = data.top_clients;
  } else if (typeof data.top_clients === 'object') {
    clients = Object.entries(data.top_clients).map(([client, count]) => ({ client, count }));
  }
} else if (data.clients) {
  if (Array.isArray(data.clients)) {
    clients = data.clients;
  } else if (typeof data.clients === 'object') {
    clients = Object.entries(data.clients).map(([client, count]) => ({ client, count }));
  }
}

if (clients.length === 0) {
  return [{ json: { message: 'No client data found.', count: 0, clients: [] } }];
}

const limited = clients.slice(0, limit);
const formatted = limited.map((c, i) => ({
  number: i + 1,
  client: c.client || c.name || c.ip || Object.keys(c)[0] || 'unknown',
  count: c.count || c.queries || c[Object.keys(c)[0]] || 0
}));

let message = 'Top clients: ';
formatted.forEach(c => {
  message += `${c.number}. ${c.client} (${Number(c.count).toLocaleString()} queries). `;
});

return [{ json: { message: message.trim(), count: formatted.length, clients: formatted } }];

const duration = $('Parse Parameters').item.json.duration;
let message = 'Pi-hole blocking disabled.';
if (duration && duration > 0) {
  if (duration >= 3600) {
    const hours = Math.floor(duration / 3600);
    const mins = Math.floor((duration % 3600) / 60);
    message = `Pi-hole blocking disabled for ${hours} hour${hours !== 1 ? 's' : ''}${mins > 0 ? ` ${mins} minute${mins !== 1 ? 's' : ''}` : ''}.`;
  } else if (duration >= 60) {
    const mins = Math.floor(duration / 60);
    message = `Pi-hole blocking disabled for ${mins} minute${mins !== 1 ? 's' : ''}.`;
  } else {
    message = `Pi-hole blocking disabled for ${duration} second${duration !== 1 ? 's' : ''}.`;
  }
}
return [{ json: { message, success: true, duration } }];

const data = $input.item.json;
const limit = $('Parse Parameters').item.json.limit;

let queries = [];
if (data.queries) {
  queries = Array.isArray(data.queries) ? data.queries : [];
} else if (data.data) {
  queries = Array.isArray(data.data) ? data.data : [];
}

if (queries.length === 0) {
  return [{ json: { message: 'No recent queries found.', count: 0, queries: [] } }];
}

const limited = queries.slice(0, limit);
const formatted = limited.map((q, i) => {
  const domain = q.domain || q.name || q[1] || 'unknown';
  const client = (typeof q.client === 'object' && q.client !== null) ? (q.client.name || q.client.ip || 'unknown') : (q.client || q.upstream || q[3] || 'unknown');
  const rawStatus = q.status || q.answer_type || q[4] || 'unknown';
  let status = String(rawStatus);
  if (['GRAVITY', 'REGEX', 'DENYLIST', 'EXTERNAL_BLOCKED'].includes(status)) {
    status = 'blocked';
  } else if (['FORWARDED', 'CACHE', 'CACHE_STALE', 'RETRIED', 'DBBUSY'].includes(status)) {
    status = 'allowed';
  }
  return { number: i + 1, domain, client, status };
});

let message = `Last ${formatted.length} queries: `;
formatted.forEach(q => {
  message += `${q.number}. ${q.domain} from ${q.client} (${q.status}). `;
});

return [{ json: { message: message.trim(), count: formatted.length, queries: formatted } }];

const errorData = $input.item.json;

if (errorData.error === true && errorData.message) {
  return [{ json: { message: errorData.message, error: true } }];
}

let errorMsg = errorData.message || errorData.error || 'Unknown error';
if (typeof errorMsg === 'object') {
  errorMsg = errorMsg.message || JSON.stringify(errorMsg);
}
errorMsg = String(errorMsg);

if (errorMsg.includes('ECONNREFUSED') || errorMsg.includes('ETIMEDOUT')) {
  errorMsg = 'Cannot connect to Pi-hole. Is it running?';
} else if (errorMsg.includes('401') || errorMsg.includes('Unauthorized') || errorMsg.includes('auth')) {
  errorMsg = 'Pi-hole authentication failed. Check the app password.';
}

return [{ json: { message: 'Pi-hole error: ' + errorMsg, error: true } }];
